import { describe, it } from "vitest";

// The test list intentionally targets the high-level runScenario surface
// for end-to-end behaviour and uses it for premium/claim arithmetic too.
// The CLI tests in the final describe block exercise src/cli.ts via a
// child process. Internal helpers (quote/claim) are an implementation
// detail of src/claim-office.ts and are not asserted on directly here.

describe("Claim Office — quote: base premiums and components", () => {
  it.todo("empty items list returns premium 5 (processing fee only)");
  it.todo("single plain sword (0 years, 1st contract) returns premium 115 (100 base + 10 first-insurance + 5 fee)");
  it.todo("single plain amulet (0 years, 1st contract) returns premium 71 (60 base + 6 first-insurance + 5 fee)");
  it.todo("single plain staff (0 years, 1st contract) returns premium 93 (80 base + 8 first-insurance + 5 fee)");
  it.todo("single plain potion (0 years, 1st contract) returns premium 49 (40 base + 4 first-insurance + 5 fee)");
  it.todo("2 runes — no block — base premium 50 G; premium 60 (50 + 5 first-insurance + 5 fee)");
  it.todo("3 runes — block applies — base premium 60 G; premium 71 (60 + 6 first-insurance + 5 fee)");
  it.todo("4 runes — no block (block requires exactly 3) — base premium 100 G; premium 115 (100 + 10 + 5)");
  it.todo("7 runes — base premium 175 G; premium 198 (175 + 17.5 + 5 = 197.5, rounded up)");
  it.todo("2 runes + 1 moonstone — different types, no block — base premium 75 G; premium 88 (75 + 7.5 + 5 = 87.5, rounded up)");
  it.todo("3 runes + 3 moonstones — two separate blocks — base premium 120 G; premium 137 (120 + 12 + 5)");
});

describe("Claim Office — quote: modifiers and thresholds", () => {
  it.todo("cursed sword (steel, enchantment 3), 0 years, 1st contract → premium 165 (100 + 50 curse + 10 first-ins + 5 fee)");
  it.todo("sword with enchantment exactly 5 (steel, not cursed), 0 years, 1st contract → premium 145 (100 + 30 high-ench + 10 + 5)");
  it.todo("sword with enchantment 4 (steel, not cursed), 0 years, 1st contract → premium 115 (no high-ench surcharge; 100 + 10 + 5)");
  it.todo("cursed sword with enchantment 5 (steel), 0 years, 1st contract → premium 195 (both surcharges stack: 100 + 50 + 30 + 10 + 5)");
  it.todo("long-standing customer (yearsWithMHPCO = 2), plain sword, 1st contract → premium 95 (100 + 10 first-ins − 20 loyalty + 5 fee)");
  it.todo("multi-item policy: cursed sword + plain amulet, 0 years, 1st contract → premium 231 (160 base + 50 curse + 16 first-ins + 5 fee); curse applies to sword's 100, not policy total");
  it.todo("long-standing customer's 2nd quote in scenario: cursed sword (steel, enchantment 7), 3 years → premium 160 (100 + 50 + 30 − 20 loyalty + 10 first-ins − 15 follow-up + 5 fee)");
});

describe("Claim Office — claim: standard reimbursement and deductible", () => {
  it.todo("regular steel sword (enchantment 3), damage 500 → payout 400 (500 − 100 deductible), remainingCap 1600 (cap 2000 − 400)");
  it.todo("rune (insurance 250), damage 200 → payout 100 (200 − 100; no special clause), remainingCap 400 (cap 500 − 100)");
  it.todo("sword + amulet policy, damages [sword 500, amulet 300] → payout 600 ((500−100)+(300−100)); deductible per damaged item; remainingCap 2600 (cap 3200 − 600)");
});

describe("Claim Office — claim: special clauses (dragon material vs. high enchantment)", () => {
  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% rule wins: 500 − 100)");
  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (only dragon-material clause: full 800 − 100)");
  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (only high-enchantment clause: 500 − 100)");
  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 → payout 400 (high-enchantment clause applies at exactly 8: 500 − 100)");
});

describe("Claim Office — claim: cap exhaustion and insurance sum", () => {
  it.todo("sword policy (insurance 1000, cap 2000): first claim of 1500 → payout 1400, remainingCap 600");
  it.todo("sword policy after a first claim leaves 600 remaining: second claim of 1500 → payout 600 (desired 1400 reduced to remaining cap), remainingCap 0");
  it.todo("sword + amulet policy → insurance sum 1600, cap 3200 (verified via a 2000 G damage scenario)");
  it.todo("sword + 3 runes (block) policy → insurance sum 1750, cap 3500; block discount does not lower the cap");
  it.todo("cursed sword → cap 2000 (based on unmodified insurance value 1000; premium modifiers do not raise the cap)");
});

describe("Claim Office — claim: payout rounding (MHPCO's favor)", () => {
  it.todo("payout calculation yielding 350.5 G is rounded down to 350 G (dragon-material sword, enchantment 9, damage 901 → (901/2) − 100 = 350.5 → 350)");
});

describe("Claim Office — claim: multiple items of the same type", () => {
  it.todo("policy with two swords → insurance sum 2000, cap 4000");
  it.todo("policy with two swords, damages [sword 500, sword 500] → payout 800 (each damage gets its own 100 deductible), remainingCap 3200");
});

describe("Claim Office — CLI surface: stdin/stdout success scenarios", () => {
  it.todo("CLI processes the schema example (amulet quote + 200 G amulet claim) and writes a results array with one quote result and one claim result, in order");
  it.todo("CLI integration — newcomer with a cursed sword: results contain { premium: 165 } for E-int1");
  it.todo("CLI integration — long-standing customer's two quotes: second quote of a cursed sword (steel, enchantment 7) for a 3-year customer produces premium 160 (E-int2)");
});

describe("Claim Office — CLI surface: error cases (non-zero exit, stderr)", () => {
  it.todo("CLI: quote includes an unknown item type ({type:'broomstick'}) → exits non-zero, writes error to stderr, no results on stdout");
  it.todo("CLI: claim references an item type not in the policy (amulet damage when only a sword is insured) → exits non-zero, error to stderr");
  it.todo("CLI: claim references an unknown item type in damages → exits non-zero, error to stderr");
  it.todo("CLI: claim contains more damage entries of a type than items insured (two sword damages, one sword in policy) → exits non-zero, error to stderr");
  it.todo("CLI: claim contains a damage entry with amount: -200 → exits non-zero, error to stderr");
});
